form:Form.form:Scripts:
		var numPage, maxPage, isSync;

function EnableBottons()
{
	 if (numPage==0)
	 {
			CtrlEnabled("btnFirst", false);
			CtrlEnabled("btnPrev" , false);
	 } else
	 {
			CtrlEnabled("btnFirst", true );
			CtrlEnabled("btnPrev" , true );
	 } 
	 if (numPage==maxPage)
	 {
			CtrlEnabled("btnNext", GetRow("19").GetAttr("EST")==""?false:true);
			CtrlEnabled("btnLast", false);
	 } else
	 {                            
			CtrlEnabled("btnNext", true);
			CtrlEnabled("btnLast", true );
	 }    

	 if (isSync)
	 {
			CtrlEnabled("btnDownload", true );
	 } else
	 {
			CtrlEnabled("btnDownload", false);
	 }
}

function OnLoad()
{ 
  Page=Ctrl("main").GetLastDocXML("PAGE");
  numPage=parseInt(Ctrl("numpage").GetXValue(),10);
  maxPage=parseInt(Ctrl("maxpage").GetXValue(),10)-1;

  isSync=true;
  EnableBottons();
	Ctrl("PAGINA_INTERFAZ").SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusRH.Base.Liquidacion.InterfazGenerica.rpt&now="+(new Date()).toString());
}      

function GetRow(id)
{                 
	return Ctrl("rows").GetRow(parseInt(id,10));
}                           

function OnLostFocusLegajo(id, value)
{                  
	myROW=GetRow(id);
	if (myROW==null) return;

	//Obtengo el Viejo y Nuevo Valor
	var oldVal=myROW.GetAttr("LEG");
	var newVal=parseInt(value,10); if (isNaN(newVal)) newVal=""; 
	                                             else newVal=newVal.toString();
	//Actualize el VALOR           
	myROW.SetAttr("LEG",newVal);
	if (newVal!=oldVal)
	{
		myROW.SetAttr("EST"     ,"1"  ); //Modificado
		myROW.SetAttr("LEG_DESC","..."); //Descriptcion Desconocida
		isSync=false; 
		EnableBottons();
	}
}

function OnLostFocusVariable(id, value)
{	
	myROW=GetRow(id);
	if (myROW==null) return;

	//Obtengo el Viejo y Nuevo Valor
	var oldVal=myROW.GetAttr("VAR");
	var newVal=Trim(value); 

	//Actualize el VALOR           
	myROW.SetAttr("VAR",newVal);
	if (newVal!=oldVal)
	{
		myROW.SetAttr("EST"     ,"1"  ); //Modificado
		myROW.SetAttr("VAR_DESC","..."); //Descriptcion Desconocida
		myROW.SetAttr("VAN"     ,"..."); //Valor Anterior Descoocido
		myROW.SetAttr("VMD"     ,""   ); //Modo
		myROW.SetAttr("VTY"     ,""   ); //Typo
		isSync=false; 
		EnableBottons();
	}
}

function OnLostFocusValor(id, value)
{
	myROW=GetRow(id);
	if (myROW==null) return;

	//Obtengo el Viejo y Nuevo Valor
	var oldVal=myROW.GetAttr("VAL");
	var newVal=Trim(value); 

	if (newVal!="")
	{  
		switch(myROW.GetAttr("VTY").toUpperCase())
		{                
			case "DATETIME":
				{ 
					var year=0, month=0, day=0;

					if (newVal.toUpperCase()=="HOY")
					{       
						year =Now().getFullYear();
						month=Now().getMonth()+1;
						day  =Now().getDate();
					} else
					if ((newVal.indexOf("-")>=0) || (newVal.indexOf("/")>=0))
					{
						var aValue;      

						if (newVal.IndexOf("-")>=0) aValue=newVal.split('-');
						                       else aValue=newVal.split('/');

						if (aValue.length==3)
						{
							year =parseInt(aValue[2],10);
							month=parseInt(aValue[1],10);
							day  =parseInt(aValue[0],10);
						} else
						if (aValue.length==2)
						{         
							year =Now().getFullYear();
							month=parseInt(aValue[1],10);
							day  =parseInt(aValue[0],10);
						} else
							year=0;

						if (month==0 && aValue.length>=2)
						{         
							month="|ENE|FEB|MAR|ABR|MAY|JUN|JUL|AGO|SEP|OCT|NOV|DIC|".indexOf("|"+aValue[1].toUpperCase()+"|");
							if (month==-1)
								year=0;
							else     
								month=month/4+1;
						}
					} else
					{
						ivalue=MyVAR.GetAttrInt("VAL");

						if (ivalue>=010100 && ivalue<=311299)
						{
							year =ivalue%100; ivalue=ivalue/100;
							month=ivalue%100; ivalue=ivalue/100;
							day  =ivalue%100; ivalue=ivalue/100;
						} else
						if (ivalue>=01011000 && ivalue<=31129999)
						{
							year =ivalue%10000; ivalue=ivalue/10000;
							month=ivalue%100; ivalue=ivalue/100;
							day  =ivalue%100; ivalue=ivalue/100;
						} else
						if (ivalue>=101 && ivalue<=3112)
						{                                  
							year =Now().getFullYear();
							month=ivalue%100; ivalue=ivalue/100;
							day  =ivalue%100; ivalue=ivalue/100;
						} else
						if (ivalue>=1 && ivalue<=31)
						{
							year =Now().getFullYear();
							month=Now().getMonth()+1;
							day  =ivalue%100; ivalue=ivalue/100;
						} else   
							year=0;
					}     

					if (year==0)
						value="";
					else
					{
						if (year<50)
						{       
							year+=2000;
						} else
						if (year<100)
						{           
							year+=1900;
						}
					}

					if (year!=0)
					{
						if (month<1 ) year=0;
						if (month>12) year=0;
					}

					value=(day+month*100+year*10000).toString();
					value=value.substr(6,2)+"/"+value.substr(4,2)+"/"+value.substr(0,4);
				} break; 

			case "DOUBLE":
				//Paso 1 - Reemplazo las Comas
				newVal=parseFloat(Replace(newVal,",","."));
				if (isNaN(newVal))
					newVal="";
				else
				{  
					//Paso 2 - Signo
					newVal=Math.round(newVal*100).toString();
					if (newVal.substr(0,1)=="-") { sgn="-"; newVal=newVal.substr(1); } else sgn="";

					///Paso 3 - Agrego '0'
					while(newVal.length<3) newVal="0"+newVal;

	    		///Paso 4 - Numero Final
					newVal=sgn+newVal.substr(0,newVal.length-2)+"."+newVal.substr(newVal.length-2);
				}
				break;

			case "INT":
				newVal=parseInt(newVal,10);
				if (isNaN(newVal)) newVal="";
				              else newVal=newVal.toString();
				break;

			case "BOOL":
				newVal=parseInt(newVal,10);
				if (isNaN(newVal)) newVal="";
				              else newVal=newVal?"1":"0";
				break;
		}

  }


	//Actualize el VALOR           
	myROW.SetAttr("VAL",newVal);
	if (newVal!=oldVal)
	{
		myROW.SetAttr("EST"     ,"1"  ); //Modificado
		isSync=false; 
		EnableBottons();
	}      


/*
	myROW=GetRow(id);
	if (myROW==null) return;

	//Paso 1 Reemplazo los Valores	
	value=Replace(value,",",".");

	//Obtengo el Viejo y Nuevo Valor
	var oldVal=myROW.GetAttr("VAL");
	var newVal=parseFloat(value); 

	if (isNaN(newVal)) 
		newVal=""; 
	else 
	{
	}

	//Actualize el VALOR
	myROW.SetAttr("VAL",newVal);
	if (newVal!=oldVal)            
	{
		myROW.SetAttr("EST","1"); //Modificado
		isSync=false; 
		EnableBottons();
	}
*/	
}

function OnLostFocusPeriodo(id, value)
{
	var month, year;

	myROW=GetRow(id);
	if (myROW==null) return;

	//Paso 1 Reemplazo los Valores	
	if (value.toUpperCase()=="HOY")
	{      
	 	month=Now().getMonth()+1;
		year =Now().getFullYear();
	} else
	if (value.indexOf("-")>=0)
	{ //mm-yyyy mmm-yyyy
		year =parseInt(value.split("-")[1],10); 
		if (isNaN(year)) 
		{     
			year=0;
		} else
		{
			if (value.split("-")[0].length==3)
			{
				month="|ENE|FEB|MAR|ABR|MAY|JUN|JUL|AGO|SEP|OCT|NOV|DIC|".indexOf("|"+value.split("-")[0].toUpperCase()+"|");
				if (month==-1) year=0;
				          else month=1+(month/4);
			} else
			 	month=parseInt(value.split("/")[0],10); if (isNaN(year)) year=0;
		}
	} else
	if (value.indexOf("/")>=0)
	{ //mm/yyyy mmm/yyyy
		year =parseInt(value.split("/")[1],10); 
		if (isNaN(year)) 
		{
			year=0;
		} else
		{
			if (value.split("/")[0].length==3)
			{
				month="|ENE|FEB|MAR|ABR|MAY|JUN|JUL|AGO|SEP|OCT|NOV|DIC|".indexOf("|"+value.split("/")[0].toUpperCase()+"|");
				if (month==-1) year=0;
				          else month=1+(month/4);
			} else
			 	month=parseInt(value.split("/")[0],10); if (isNaN(year)) year=0;
		}
	} else
	{    
		newVal=parseInt(value,10);
		if (isNaN(newVal)) 
		{  
				year=Now().getFullYear();
				month="|ENE|FEB|MAR|ABR|MAY|JUN|JUL|AGO|SEP|OCT|NOV|DIC|".indexOf("|"+value.toUpperCase()+"|");
				if (month==-1) year=0;
				          else month=1+(month/4);
		} else
		{
			if (newVal>=1 && newVal<=12)
			{       
				month=newVal;
				year =Now().getFullYear();
			} else
			if (newVal>=100 && newVal<=1299)
			{
				month=newVal/100;
				year =newVal%100;
			} else
			if (newVal>=011000 && newVal<=129999)
			{
				month=newVal/10000;
				year =newVal%10000;
			} else
			{
				year=0;
			}
		}
	}


	var oldVal=myROW.GetAttr("PER");
	if (year==0)
	{
		newVal="";
	} else
	if (year>=0 && year<50)
	{
		newVal=((year+2000)*100+month).toString();
	} else
	if (year>=50 && year<=99)
	{
		newVal=((year+1900)*100+month).toString();
	} else
	{
		newVal=(year*100+month).toString();
	}      

	if (newVal!="") newVal=newVal.substr(4,2)+"/"+newVal.substr(0,4);

	//Actualize el VALOR           
	myROW.SetAttr("PER",newVal);
	if (newVal!=oldVal)
	{
		myROW.SetAttr("EST", "1"); //Modificado
		isSync=false; 
		EnableBottons();
	}
}

function CleanRow(id)
{
	myROW=GetRow(id);
	if (myROW==null) return;
	if (myROW.GetAttr("EST")=="") return;

	//Cambio el Estado
	myROW.SetAttr("EST","1");
	isSync=false; 
	EnableBottons();  

	//Limpio los Registros
	myROW.SetAttr("LEG","");
	myROW.SetAttr("LEG_DESC","");
	myROW.SetAttr("VAR","");
	myROW.SetAttr("VAR_DESC","");
	myROW.SetAttr("VAL","");
	myROW.SetAttr("PER","");
	myROW.SetAttr("VMD","");
	myROW.SetAttr("VTY","");
	myROW.SetAttr("ERR","");
}

function Refresh()
{                                
	Ctrl("main").DoEvent("Refresh");
}

function First()
{                                
	if (numPage<=0) return;            

	Ctrl("topage").SetXValue("0");
	Ctrl("main").DoEvent("ToPage");
}

function Prev()
{                                
	if (numPage<=0) return;            

	Ctrl("topage").SetXValue((numPage-1).toString());
	Ctrl("main").DoEvent("ToPage");
}

function Next()
{                                
	Ctrl("topage").SetXValue((numPage+1).toString());
	Ctrl("main").DoEvent("ToPage");
}

function Last()
{    
	if (numPage>=maxPage) return;            

	Ctrl("topage").SetXValue(maxPage.toString());
	Ctrl("main").DoEvent("ToPage");
}

function Download()
{
	DownloadFile("INTERFACES\\"+GetProxy().UserName()+".intvar.xml", "intvar.xml");
}

function ObjectUpload(MyOBJ, fileName)
{
	var retval=MyOBJ;                   
	retval.FileName=fileName;

	retval.processResult= function(xmlin)
	{  
		var proxy=GetProxy(); //as NomadProxy

		//Eliminar el Archivo
		if (proxy.FileSystem().FileExist(".\\Nomad\\INTERFACES\\"+GetProxy().UserName()+".intvar.xml"))
			proxy.FileSystem().Delete(".\\Nomad\\INTERFACES\\"+GetProxy().UserName()+".intvar.xml");

		//Mover el ARCHIVO
		proxy.FileSystem().Move(".\\Nomad\\Temp\\"+fileName,".\\Nomad\\INTERFACES\\"+GetProxy().UserName()+".intvar.xml");

		//Reset
		Ctrl("main").DoEvent("Reset");
	}     
	return retval;
}  

function Upload(MyOBJ)
{
	var arrParams = new Array();
	arrParams[0] = "FOLDER";
	arrParams[1] = "TEMP";
	arrParams[2] = datetime2str(new Date()) + ".intvar.xml";

	showBrowse(ObjectUpload(MyOBJ, datetime2str(new Date()) + ".intvar.xml"), arrParams);
}

function CheckLiq(obj)
{
	if (Ctrl("Liquidacion").GetXValue()=="")
	{            
		obj.SetError("La liquidacion es Requerida.");	
		return false;
	} 
	return true;
}
